sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;
    if (!newValue) return;

    var weight = parseFloat(newValue);
    if (isNaN(weight) || weight < 50) {
        g_form.showFieldMsg('weight', 'Weight must be at least 50 kg.', 'error');
    } else {
        g_form.hideFieldMsg('weight');
    }
}
